177: func (sch *schedule) Run(ctx context.Context) error {
178: 	sch.log.Info("Starting scheduler", "tickInterval", sch.baseInterval, "maxAttempts", sch.retryConfig.MaxAttempts)
179: 	t := ticker.New(sch.clock, sch.baseInterval, sch.metrics.Ticker, sch.log)
180: 	defer t.Stop()
181: 
182: 	if err := sch.schedulePeriodic(ctx, t); err != nil {
183: 		sch.log.Error("Failure while running the rule evaluation loop", "error", err)
184: 	}
185: 	return nil
186: }
