188: // Rules fetches the entire set of rules considered for evaluation by the scheduler on the next tick.
189: // Such rules are not guaranteed to have been evaluated by the scheduler.
190: // Rules returns all supplementary metadata for the rules that is stored by the scheduler - namely, the set of folder titles.
191: func (sch *schedule) Rules() ([]*ngmodels.AlertRule, map[ngmodels.FolderKey]string) {
192: 	return sch.schedulableAlertRules.all()
193: }
