195: // Status fetches the health of a given scheduled rule, by key.
196: func (sch *schedule) Status(_ context.Context, key ngmodels.AlertRuleKey) (ngmodels.RuleStatus, bool) {
197: 	if rule, ok := sch.registry.get(key); ok {
198: 		return rule.Status(), true
199: 	}
200: 	return ngmodels.RuleStatus{}, false
201: }
