229: func (sch *schedule) getRuleStopReason(ctx context.Context, key ngmodels.AlertRuleKeyWithGroup) error {
230: 	// If the ruleStopReasonProvider is defined, we will use it to get the reason why the
231: 	// alert rule was stopped. If it returns an error, we will use the default reason.
232: 	if sch.ruleStopReasonProvider == nil {
233: 		return errRuleDeleted
234: 	}
235: 
236: 	stopReason, err := sch.ruleStopReasonProvider.FindReason(ctx, sch.log, key)
237: 	if err != nil {
238: 		sch.log.New(key.LogContext()...).Error("Failed to get stop reason", "error", err)
239: 		return errRuleDeleted
240: 	}
241: 	if stopReason == nil {
242: 		return errRuleDeleted
243: 	}
244: 
245: 	return stopReason
246: }
