248: func (sch *schedule) schedulePeriodic(ctx context.Context, t *ticker.T) error {
249: 	dispatcherGroup, ctx := errgroup.WithContext(ctx)
250: 	for {
251: 		select {
252: 		case tick := <-t.C:
253: 			// We use Round(0) on the start time to remove the monotonic clock.
254: 			// This is required as ticks from the ticker and time.Now() can have
255: 			// a monotonic clock that when subtracted do not represent the delta
256: 			// in wall clock time.
257: 			start := time.Now().Round(0)
258: 			sch.metrics.BehindSeconds.Set(start.Sub(tick).Seconds())
259: 
260: 			sch.processTick(ctx, dispatcherGroup, tick)
261: 
262: 			sch.metrics.SchedulePeriodicDuration.Observe(time.Since(start).Seconds())
263: 		case <-ctx.Done():
264: 			// waiting for all rule evaluation routines to stop
265: 			waitErr := dispatcherGroup.Wait()
266: 			return waitErr
267: 		}
268: 	}
269: }
