284: 	if updated == nil { // make sure map is not nil
285: 		updated = map[ngmodels.AlertRuleKey]struct{}{}
286: 	}
287: 	if err != nil {
288: 		sch.log.Error("Failed to update alert rules", "error", err)
289: 	}
