429: // runJobFn sends the scheduled evaluation to the evaluation routine, optionally with a previous item to log the trigger source.
430: func (sch *schedule) runJobFn(next readyToRunItem, prev ...readyToRunItem) func() {
431: 	return func() {
432: 		if len(prev) > 0 {
433: 			sch.log.Debug("Rule evaluation triggered by previous rule", append(next.rule.GetKey().LogContext(), "previousRule", prev[0].rule.UID)...)
434: 		}
435: 		key := next.rule.GetKey()
436: 		success, dropped := next.ruleRoutine.Eval(&next.Evaluation)
437: 		if !success {
438: 			sch.log.Debug("Scheduled evaluation was canceled because evaluation routine was stopped", append(key.LogContext(), "time", next.scheduledAt)...)
439: 			return
440: 		}
441: 		if dropped != nil {
442: 			sch.log.Warn("Tick dropped because alert rule evaluation is too slow", append(key.LogContext(), "time", next.scheduledAt, "droppedTick", dropped.scheduledAt)...)
443: 			orgID := fmt.Sprint(key.OrgID)
444: 			sch.metrics.EvaluationMissed.WithLabelValues(orgID, next.rule.Title).Inc()
445: 		}
446: 	}
447: }
