449: func (sch *schedule) runSequences(sequences []sequence, step int64) {
450: 	for i := range sequences {
451: 		time.AfterFunc(time.Duration(int64(i)*step), sch.runJobFn(readyToRunItem(sequences[i])))
452: 	}
453: }
